import{c as t,Q as a,j as o,m as n}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Troubleshooting & FAQ","description":"Fixes for the common stalls when testing MuHaven — encrypted-balance buy-gate, faucet limits, passkey RP-ID, and async waits.","frontmatter":{"title":"Troubleshooting & FAQ","description":"Fixes for the common stalls when testing MuHaven — encrypted-balance buy-gate, faucet limits, passkey RP-ID, and async waits."},"headers":[],"relativePath":"guide/troubleshooting.md","filePath":"guide/troubleshooting.md","lastUpdated":1780218602000}'),r={name:"guide/troubleshooting.md"};function s(i,e,l,u,d,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="troubleshooting-faq" tabindex="-1">Troubleshooting &amp; FAQ <a class="header-anchor" href="#troubleshooting-faq" aria-label="Permalink to &quot;Troubleshooting &amp; FAQ&quot;">​</a></h1><p>Most &quot;it&#39;s stuck&quot; moments are one of a handful of expected behaviours. Search this page (press <kbd>/</kbd>) for your symptom.</p><h2 id="buy-gate" tabindex="-1">The buy button is disabled and asks me to &quot;Reveal&quot; <a class="header-anchor" href="#buy-gate" aria-label="Permalink to &quot;The buy button is disabled and asks me to &quot;Reveal&quot; {#buy-gate}&quot;">​</a></h2><p><strong>This is expected, not a bug.</strong> Your mhUSDC balance is encrypted, so the app can&#39;t tell whether it covers the purchase until you reveal it.</p><p><strong>Fix:</strong> click <strong>Reveal mhUSDC balance</strong> in the trade form. It&#39;s a one-tap local decrypt (a permit) — <strong>no transaction, no on-chain leak</strong>. Once revealed:</p><ul><li>If you have enough, the <strong>Buy</strong> button enables.</li><li>If you&#39;re short, you&#39;ll see a <strong>Short $X</strong> hint and a <strong>Top up cash</strong> link to <a href="/guide/investor/deposit">Deposit</a>.</li></ul><p>Full detail: <a href="/guide/investor/buy">I5 · Buy a position</a>.</p><h2 id="faucet-limits" tabindex="-1">The faucet won&#39;t give me USDC <a class="header-anchor" href="#faucet-limits" aria-label="Permalink to &quot;The faucet won&#39;t give me USDC {#faucet-limits}&quot;">​</a></h2><p>Circle&#39;s faucet limits how much each address can claim per time window.</p><p><strong>Fixes:</strong></p><ul><li>Wait out the cooldown and try again — you only need a small amount (≈ $100 test USDC) for the whole guide.</li><li>Fund a <strong>second address</strong> (create another account) if you need more immediately.</li><li>Make sure you selected <strong>Arbitrum Sepolia</strong> (not Ethereum Sepolia or another chain) in the faucet.</li></ul><p>You do <strong>not</strong> need ETH — gas is sponsored.</p><h2 id="passkey-rp-id" tabindex="-1">My passkey &quot;isn&#39;t valid for this domain&quot; <a class="header-anchor" href="#passkey-rp-id" aria-label="Permalink to &quot;My passkey &quot;isn&#39;t valid for this domain&quot; {#passkey-rp-id}&quot;">​</a></h2><p>A passkey is cryptographically bound to the <strong>exact domain</strong> where you created it (WebAuthn &quot;RP ID&quot;). A passkey made on a staging or local URL won&#39;t authenticate on the production app, and vice-versa.</p><p><strong>Fix:</strong> register a <strong>fresh passkey on the domain you&#39;re testing</strong>. For the public app that&#39;s <a href="https://muhaven.app" target="_blank" rel="noreferrer">muhaven.app</a>. If you previously made a passkey on an old domain, just create a new account on the current one.</p><h2 id="async-waits" tabindex="-1">A step is taking longer than I expected <a class="header-anchor" href="#async-waits" aria-label="Permalink to &quot;A step is taking longer than I expected {#async-waits}&quot;">​</a></h2><p>Some flows are intentionally asynchronous:</p><table tabindex="0"><thead><tr><th>Flow</th><th>Typical wait</th><th>Why</th></tr></thead><tbody><tr><td>Any single transaction</td><td>~30–60s</td><td>One Arbitrum Sepolia block to confirm.</td></tr><tr><td><strong>Withdraw mhUSDC → USDC</strong></td><td>~1–3 min (sometimes more)</td><td>Two phases: burn, then a homomorphic-decryption round-trip, then the USDC payout. See <a href="/guide/investor/withdraw">I11</a>.</td></tr><tr><td><strong>Yield distribution</strong> (issuer)</td><td>~30–60s per phase</td><td>Encrypted snapshot + coprocessor decrypt. See <a href="/guide/issuer/distribute-yield">S3</a>.</td></tr><tr><td><strong>Redemption-queue settlement</strong></td><td>Until the next epoch processes</td><td>Your over-cap sell settles in a later round. See <a href="/guide/investor/redemption-queue">I9</a>.</td></tr></tbody></table><p>If a page shows a spinner past these windows, refresh — most flows <strong>resume from on-chain state</strong> and won&#39;t lose your progress.</p><h2 id="encrypted-balance" tabindex="-1">My balance shows a lock icon instead of a number <a class="header-anchor" href="#encrypted-balance" aria-label="Permalink to &quot;My balance shows a lock icon instead of a number {#encrypted-balance}&quot;">​</a></h2><p>That&#39;s the encrypted balance. Click <strong>Reveal</strong> (the eye icon) to decrypt it <strong>locally</strong> for your eyes only. Nothing is sent on-chain; no one else can reveal your balance. See <a href="/guide/investor/reveal-balance">I6 · Reveal your balance</a>.</p><h2 id="i-can-t-buy-a-specific-token-—-it-says-not-listed-or-winding-down" tabindex="-1">I can&#39;t buy a specific token — it says &quot;not listed&quot; or &quot;winding down&quot; <a class="header-anchor" href="#i-can-t-buy-a-specific-token-—-it-says-not-listed-or-winding-down" aria-label="Permalink to &quot;I can&#39;t buy a specific token — it says &quot;not listed&quot; or &quot;winding down&quot;&quot;">​</a></h2><p>Token availability is per-token state:</p><ul><li><strong>Not yet listed on-chain</strong> — the token isn&#39;t deployed/active yet; the buy CTA is disabled.</li><li><strong>Winding down / view-only</strong> — the token is being retired; you can sell but not buy.</li></ul><p>Pick another token from the <a href="/guide/investor/marketplace">marketplace</a>.</p><h2 id="a-buy-fails-with-a-stale-nav-style-error" tabindex="-1">A buy fails with a &quot;stale NAV&quot; style error <a class="header-anchor" href="#a-buy-fails-with-a-stale-nav-style-error" aria-label="Permalink to &quot;A buy fails with a &quot;stale NAV&quot; style error&quot;">​</a></h2><p>Each token&#39;s price (NAV) must be fresh (updated within the last day) for a buy to go through. On the demo testnet this is normally kept current. If you hit it, try again shortly or pick another token — it&#39;s a freshness gate, not a problem with your account.</p><h2 id="the-agent-won-t-execute-a-trade-on-its-own" tabindex="-1">The agent won&#39;t execute a trade on its own <a class="header-anchor" href="#the-agent-won-t-execute-a-trade-on-its-own" aria-label="Permalink to &quot;The agent won&#39;t execute a trade on its own&quot;">​</a></h2><p>Autonomous execution requires a <strong>scoped session</strong> at the right tier. If the agent only <em>proposes</em> (gives you a confirm link), either:</p><ul><li>you&#39;re in <strong>Advisory / Confirm-per-action</strong> — approve the action the agent surfaces (a confirmation modal in the dashboard, or a deep-link you sign with your passkey), or</li><li>you haven&#39;t armed a <strong>Scoped</strong> session yet — do that in <a href="/guide/agent/set-tier">H3 · Arm Scoped autonomy</a>.</li></ul><p>To stop the agent at any time, just ask it — e.g. <em>&quot;pause my agent&quot;</em> — which blocks every write instantly. You can also revoke the session from the dashboard or via Telegram.</p><h2 id="asking-the-agent-to-rebalance-via-an-external-mcp-tool-returns-not-implemented" tabindex="-1">Asking the agent to &quot;rebalance&quot; via an external MCP tool returns &quot;not implemented&quot; <a class="header-anchor" href="#asking-the-agent-to-rebalance-via-an-external-mcp-tool-returns-not-implemented" aria-label="Permalink to &quot;Asking the agent to &quot;rebalance&quot; via an external MCP tool returns &quot;not implemented&quot;&quot;">​</a></h2><p>Multi-leg <strong>rebalance runs through HavenBot in the dashboard</strong> (and the Portfolio &quot;Rebalance to targets&quot; panel), not the standalone external <code>position.rebalance</code> MCP tool, which intentionally returns <code>not_implemented</code>. Use HavenBot — see <a href="/guide/agent/autonomous">H4 · Buy &amp; sell autonomously</a>.</p><h2 id="a-feature-returns-not-deployed" tabindex="-1">A feature returns &quot;not deployed&quot; <a class="header-anchor" href="#a-feature-returns-not-deployed" aria-label="Permalink to &quot;A feature returns &quot;not deployed&quot;&quot;">​</a></h2><p><code>governance.*</code>, <code>read.protection_coverage</code>, and <code>read.kyc_attestation</code> return <code>not_deployed</code> because those P11 contracts aren&#39;t on the demo testnet. That&#39;s expected — see <a href="/guide/not-in-this-guide">Not in this guide</a>.</p><h2 id="still-stuck" tabindex="-1">Still stuck? <a class="header-anchor" href="#still-stuck" aria-label="Permalink to &quot;Still stuck?&quot;">​</a></h2><ul><li>Re-check <a href="/guide/before-you-begin">Before you begin</a>.</li><li>Confirm the app version in the footer matches the latest deploy (rule out a cached tab — hard-refresh with <kbd>Ctrl/Cmd</kbd>+<kbd>Shift</kbd>+<kbd>R</kbd>).</li><li>Browse the deeper <a href="/havenbot/troubleshooting">HavenBot</a> and <a href="/mcp/troubleshooting">MCP</a> troubleshooting pages.</li></ul>',37)])])}const g=t(r,[["render",s]]);export{p as __pageData,g as default};
